const { target_host, target_type, since_hours, session_id } = $('📥 Input').first().json;
if (!target_host) throw new Error('target_host ist erforderlich');
const cmd = `journalctl -p err..emerg --since "${since_hours || 24} hours ago" --no-pager -o json | head -500`;
return { target_host, target_type: target_type || 'lxc', since_hours: since_hours || 24,
  command: cmd, session_id: session_id || require('crypto').randomUUID() };

const input = $('📥 Input').first().json;
const ssh_result = $('💻 SUB: SSH Execute').first().json;
const logs = ssh_result?.data?.stdout || '(keine Logs)';
return { prompt: `Analysiere folgende System-Logs von ${input.target_host} (${input.target_type}) der letzten ${input.since_hours}h:\n\n${logs.substring(0,8000)}\n\nIdentifiziere: 1) Kritische Fehler 2) Warnungen 3) Muster 4) Handlungsempfehlungen. Antworte als JSON: {severity, issues:[{type,message,count,recommendation}], summary, requires_action}`,
  model: 'claude-sonnet-4-6', max_tokens: 2000, session_id: input.session_id };

const input = $('📥 Input').first().json;
const claude = $('🤖 SUB: Claude').first().json;
const result = typeof claude.response === 'string' ? JSON.parse(claude.response) : claude.response || {};
return { exit_code: 'success', session_id: input.session_id,
  data: { target_host: input.target_host, target_type: input.target_type,
    severity: result.severity || 'unknown', issues: result.issues || [],
    summary: result.summary || 'Keine Zusammenfassung', requires_action: result.requires_action || false },
  timestamp: new Date().toISOString() };
